        // 동영상 url 구분하기
        function getVideoDetails( url )
        {
            try
            {
                const urlObj = new URL( url );

                let site = "";
                let videoID = "";

                if( urlObj.hostname.includes( "youtube.com" ) || urlObj.hostname.includes( "youtu.be" ) )
                {
                    site = "youtube";
                    if( urlObj.hostname.includes( "youtube.com" ) )
                    {
                        const shortsIndex = url.indexOf("/shorts/");
                        if( shortsIndex !== -1 )
                        {
                            let videoIDWithParams = url.substring( shortsIndex + 8 );
                            const paramIndex = videoIDWithParams.indexOf( "?" );
                            if( paramIndex !== -1 )
                                videoID = videoIDWithParams.substring( 0, paramIndex );
                            else
                                videoID = videoIDWithParams;
                        }
                        else
                        {
                            videoID = urlObj.searchParams.get( "v" );
                        }
                    }
                    else if( urlObj.hostname.includes( "youtu.be" ) )
                    {
                        videoID = urlObj.pathname.slice( 1 );
                    }
                }
                else if( urlObj.hostname.includes( "vimeo.com" ) )
                {
                    site = "vimeo";
                    if( urlObj.hostname.includes( "player.vimeo.com" ) )
                        videoID = urlObj.pathname.split( "/" )[ 2 ];
                    else
                        videoID = urlObj.pathname.split( "/" )[ 1 ];
                }
                else if( urlObj.hostname.includes( "charlla.io" ) )
                {
                    const pathparts = urlObj.pathname.split("/").filter(Boolean);
                    if (urlObj.hostname.includes("player.charlla.io") && pathparts[0] === "shoplayer") {
                        site = "shoplayer";
                        videoID = urlObj.pathname.split( "/" )[ 2 ];
                    } else {
                        site = "charlla";
                        videoID = urlObj.pathname.split( "/" )[ 1 ];
                    }
        
                    //site = "charlla";
                    //videoID = urlObj.pathname.split( "/" )[ 1 ];
                }
                else if( urlObj.pathname.endsWith( ".mp4" ) )
                {
                    site = "mp4";
                    videoID = urlObj.pathname;
                }
                else
                {
                    site = "unknown";
                    videoID = null;
                }

                return { site, videoID };
            }
            catch( error )
            {
                console.error( "유효한 URL이 아닙니다:", error );
                return null;
            }
        }

        function makeVideoTag( html, data )
        {
            for( let i in data.videoUrl )
            {
                const urlData = data.videoUrl[ i ];
                if( null == urlData.url || "undefined" == urlData.url || "" == urlData.url )
                {
                    switch( i )
                    {
                        case "0" : html = html.replace( /{#video_1}/gi, "" ); break;
                        case "1" : html = html.replace( /{#video_2}/gi, "" ); break;
                        case "2" : html = html.replace( /{#video_3}/gi, "" ); break;
                    }

                    continue;
                }
                
                const siteUrl = getVideoDetails( urlData.url );
                if( null == siteUrl )
                {
                    switch( i )
                    {
                        case "0" : html = html.replace( /{#video_1}/gi, "" ); break;
                        case "1" : html = html.replace( /{#video_2}/gi, "" ); break;
                        case "2" : html = html.replace( /{#video_3}/gi, "" ); break;
                    }

                    continue;
                }

                let pointerEvent = "";
                if( true == urlData.autoPlay )
                    pointerEvent = "pointer-events:none;"
                else
                    pointerEvent = "pointer-events:auto;"

                let aspectRatio = urlData.ratioX + "/" + urlData.ratioY;
                
                let iframeElem = "";
                switch( siteUrl.site )
                {
                    case "youtube" :
                    {
                        iframeElem = "<div class=\"m_iframe_box\"><iframe src=\"//youtube.com/embed/" + siteUrl.videoID + 
                            "?background=1&enablejsapi=1&mute=1&controls=0&loop=1&playlist=" + siteUrl.videoID + 
                            "&autoplay=" + urlData.autoPlay + 
                            "\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" loading=\"lazy\" style=\"width:100%;height:100%;" + 
                            pointerEvent + "aspect-ratio:" + aspectRatio + "\"></iframe></div>";
                    }
                    break;
        
                    case "vimeo" :
                    {
                        iframeElem = "<div class=\"m_iframe_box\"><iframe src=\"//player.vimeo.com/video/" + siteUrl.videoID + 
                            "?background=1&enablejsapi=1&muted=1&portrait=0&loop=1&title=0&byline=0&autoplay=" + urlData.autoPlay + 
                            "\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" loading=\"lazy\" style=\"width:100%;height:100%;" + 
                            pointerEvent + "aspect-ratio:" + aspectRatio + "\"></iframe></div>";
                    }
                    break;
        
                    case "charlla" :
                    {
                        iframeElem = "<div class=\"m_iframe_box\"><iframe src=\"//player.charlla.io/" + siteUrl.videoID + 
                            "?background=1&enablejsapi=1&cover\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" loading=\"lazy\" style=\"width:100%;height:100%;" 
                            + pointerEvent + "aspect-ratio:" + aspectRatio + "\"></iframe></div>";
                    }
                    break;

                    case "shoplayer" :
                    {
                        iframeElem = "<div class=\"m_iframe_box\"><iframe src=\"//player.charlla.io/shoplayer/" + siteUrl.videoID +
                            "?cover\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" loading=\"lazy\" style=\"width:100%;height:100%;"
                            + pointerEvent + "aspect-ratio:" + aspectRatio + "\"></iframe></div>";
                    }
                    break;

                    case "mp4" :
                    {
                        let autoplay_chk = "";
                        if( true == urlData.autoPlay )
                            autoplay_chk = "autoplay";
        
                        iframeElem = "<div class=\"m_iframe_box\"><video src=\"" + urlData.url + 
                            "\" " + autoplay_chk + 
                            " muted playsinline loop loading=\"lazy\" style=\"width:100%;height:100%;" + 
                            pointerEvent + "aspect-ratio:" + aspectRatio + "\"></video></div>";
                    }
                    break;
        
                    default :
                    {
                        console.log( "영상없음" );
                    }
                    break;
                }

                switch( i )
                {
                    case "0" : html = html.replace( /{#video_1}/gi, iframeElem ); break;
                    case "1" : html = html.replace( /{#video_2}/gi, iframeElem ); break;
                    case "2" : html = html.replace( /{#video_3}/gi, iframeElem ); break;
                }
            }

            return html;
        }

